import React, { useState, useEffect, useRef } from 'react';
import { 
  Activity, Settings, Play, Database, Shield, Zap, 
  TrendingUp, RefreshCw, LogOut, CheckCircle2, AlertCircle,
  Globe, Server, User, Key, Mail, Cpu, Clock, DollarSign
} from 'lucide-react';
import { io } from 'socket.io-client';
import { auth, db } from './lib/firebase';
import { onAuthStateChanged, signOut, GoogleAuthProvider, signInWithPopup } from 'firebase/auth';
import { collection, addDoc, onSnapshot, query, orderBy, limit } from 'firebase/firestore';

// ==========================================
// CONFIGURACI├ôN DE N├ÜCLEO (BLINDAJE v6.2)
// ==========================================

const App = () => {
  const [user, setUser] = useState(null);
  const [activeTab, setActiveTab] = useState('panel');
  const [gatewayUrl, setGatewayUrl] = useState(localStorage.getItem('trade_gateway') || '');
