  // 2. CONEXI├ôN SOCKET DIN├üMICA
  useEffect(() => {
    if (!user || !gatewayUrl) return;

    if (socketRef.current) socketRef.current.disconnect();

    try {
      socketRef.current = io(gatewayUrl, { 
